mapper.select:
SELECT id, chat_room_id, user_id, last_read_message_id, last_read_at, joined_at, left_at
FROM chat_room_members
WHERE chat_room_id = #{chatRoomId}
  AND user_id = #{userId}

mapper.update:
UPDATE chat_room_members
SET last_read_message_id = #{lastReadMessageId},
    last_read_at = #{lastReadAt}
WHERE chat_room_id = #{chatRoomId}
  AND user_id = #{userId}

UPDATE chat_room_members
SET left_at = #{leftAt}
WHERE chat_room_id = #{chatRoomId}
  AND user_id = #{userId}

UPDATE chat_room_members
SET left_at = NULL
WHERE chat_room_id = #{chatRoomId}
  AND user_id = #{userId}
